import subprocess

def generate_lock_file(lock_file_path):
    subprocess.run(["poetry", "lock"])
    subprocess.run(["poetry", "export", "-f", "requirements.txt", "-o", lock_file_path])

def update_lock_file(lock_file_path):
    subprocess.run(["poetry", "update"])
    subprocess.run(["poetry", "export", "-f", "requirements.txt", "-o", lock_file_path])

# Usage
# Generate lock file
generate_lock_file("requirements.txt")

# Update lock file
update_lock_file("requirements.txt")